1	import { describe, it, expect } from "vitest";
2	import { processScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // === Simplest cases ===
6	  it("empty item list → premium 5 G (only processing fee)", () => {
7	    const result = processScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result).toEqual({ results: [{ premium: 5 }] });
12	  });
13	
14	  // === Base premiums for individual items (with processing fee) ===
15	  it("single sword (newcomer, first quote) → premium 115 G (100 + 10 first ins + 5 fee)", () => {
16	    const result = processScenario({
17	      customer: { yearsWithMHPCO: 0 },
18	      steps: [{ op: "quote", items: [{ type: "sword" }] }],
19	    });
20	    expect(result).toEqual({ results: [{ premium: 115 }] });
21	  });
22	  it("single amulet (newcomer, first quote) → premium 71 G (60 + 6 first ins + 5 fee)", () => {
23	    const result = processScenario({
24	      customer: { yearsWithMHPCO: 0 },
25	      steps: [{ op: "quote", items: [{ type: "amulet" }] }],
26	    });
27	    expect(result).toEqual({ results: [{ premium: 71 }] });
28	  });
29	  it("single staff (newcomer) → premium 93 G (80 + 8 first ins + 5 fee)", () => {
30	    const result = processScenario({
31	      customer: { yearsWithMHPCO: 0 },
32	      steps: [{ op: "quote", items: [{ type: "staff" }] }],
33	    });
34	    expect(result).toEqual({ results: [{ premium: 93 }] });
35	  });
36	  it("single potion (newcomer) → premium 49 G (40 + 4 first ins + 5 fee)", () => {
37	    const result = processScenario({
38	      customer: { yearsWithMHPCO: 0 },
39	      steps: [{ op: "quote", items: [{ type: "potion" }] }],
40	    });
41	    expect(result).toEqual({ results: [{ premium: 49 }] });
42	  });
43	
44	  // === Components ===
45	  it("single rune (newcomer) → premium 33 G (ceil(25*1.1)=28 + 5 fee)", () => {
46	    const result = processScenario({
47	      customer: { yearsWithMHPCO: 0 },
48	      steps: [{ op: "quote", items: [{ type: "rune" }] }],
49	    });
50	    expect(result).toEqual({ results: [{ premium: 33 }] });
51	  });
52	  it.todo("single moonstone → premium 30 G (25 base + 5 fee)");
53	  it("2 runes (newcomer) → premium 60 G (2×25=50 base + 5 first ins + 5 fee, no block)", () => {
54	    const result = processScenario({
55	      customer: { yearsWithMHPCO: 0 },
56	      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }] }],
57	    });
58	    expect(result).toEqual({ results: [{ premium: 60 }] });
59	  });
60	  it.todo("3 runes → premium 65 G (60 block + 5 fee)");
61	  it.todo("4 runes → premium 105 G (100 base, no block — block requires exactly 3)");
62	  it.todo("7 runes → premium 180 G (175 base + 5 fee)");
63	
64	  // === Alike components — block requires same type ===
65	  it.todo("2 runes + 1 moonstone → premium 80 G (75 base + 5 fee, no block)");
66	  it.todo("3 runes + 3 moonstones → premium 125 G (120 base + 5 fee, two separate blocks)");
67	
68	  // === Item-specific modifiers ===
69	  it.todo("cursed sword → premium 155 G (100 + 50 curse + 5 fee)");
70	  it.todo("sword enchantment 5 → premium 135 G (100 + 30 high-ench + 5 fee)");
71	  it.todo("sword enchantment 4 → premium 105 G (no high-ench surcharge)");
72	  it.todo("cursed sword enchantment 5 → premium 185 G (100 + 50 + 30 + 5)");
73	
74	  // === Policy-wide modifiers ===
75	  it.todo("loyalty: 2 years exactly → 20% discount applies (sword: 100 - 20 + 5 = 85)");
76	  it.todo("loyalty: 1 year → no discount (sword: 100 + 5 = 105)");
77	  it.todo("first insurance (first quote) → 10% surcharge added");
78	  it.todo("second quote → 15% follow-up discount applies");
79	
80	  // === Modifier scope on multi-item policies ===
81	  it.todo("cursed sword + plain amulet → 215 G (item-specific curse on sword only) [100+60=160, +50 curse, +10 first ins on 100, +5 fee = 225? recheck]");
82	  it.todo("modifier scope: item-specific applies to item base, policy-wide to total");
83	
84	  // === Rounding (in MHPCO's favor) ===
85	  it.todo("premium yielding 197.5 G → rounded up to 198 G");
86	  it.todo("payout yielding 350.5 G → rounded down to 350 G");
87	
88	  // === Integration examples ===
89	  it.todo("newcomer with cursed sword (steel, ench 3) → premium 165 G");
90	  it.todo("long-standing customer (3 years), second contract, cursed sword ench 7 → 160 G");
91	
92	  // === Claim: standard reimbursement ===
93	  it.todo("regular sword (steel, ench 3), damage 500 → payout 400");
94	  it.todo("damage to rune (insurance 250), damage 200 → payout 100");
95	
96	  // === Claim: high enchantment clause ===
97	  it.todo("steel sword ench 9, damage 1000 → payout 400 (50% then deductible)");
98	
99	  // === Claim: dragon material clause ===
100	  it.todo("dragon sword ench 5, damage 800 → payout 700 (full minus deductible)");
101	
102	  // === Claim: both clauses (50% wins) ===
103	  it.todo("dragon sword ench 9, damage 1000 → payout 400 (50% wins, then deductible)");
104	  it.todo("dragon sword ench 8 exactly, damage 1000 → payout 400 (high-ench wins, then deductible)");
105	
106	  // === Deductible per damage event (per item) ===
107	  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 (deductible per item)");
108	
109	  // === Multiple items of same type ===
110	  it.todo("policy with two swords, both damaged → each gets own deductible");
111	  it.todo("damage entries exceed insured count → claim rejected (non-zero exit)");
112	
113	  // === Cap on policy ===
114	  it.todo("sword (cap 2000), claim 1500 → payout 1400, remainingCap 600");
115	  it.todo("sword (cap 2000), second claim 1500 after 1400 paid → payout 600, remainingCap 0");
116	  it.todo("cursed sword cap 2000 (based on unmodified insurance value)");
117	  it.todo("sword + 3 runes block → insurance sum 1750 (block affects premium, not sum)");
118	
119	  // === Error handling ===
120	  it.todo("quote with unknown item type → CLI exits non-zero, error on stderr");
121	  it.todo("claim references item not in policy → CLI exits non-zero, error on stderr");
122	  it.todo("claim with negative damage amount → CLI exits non-zero, error on stderr");
123	});
