1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_PERCENT = 10;
3	
4	interface Item {
5	  type: string;
6	}
7	interface QuoteStep {
8	  op: "quote";
9	  items: Item[];
10	}
11	interface Scenario {
12	  customer: { yearsWithMHPCO: number };
13	  steps: QuoteStep[];
14	}
15	
16	const BASE_PREMIUM: Record<string, number> = {
17	  sword: 100,
18	  amulet: 60,
19	  staff: 80,
20	  potion: 40,
21	  rune: 25,
22	};
23	
24	// Per spec: intermediate amounts are kept as fractions; only the final
25	// premium is rounded (up, in MHPCO's favour).
26	const applyPercentSurcharge = (base: number, percent: number): number =>
27	  (base * (100 + percent)) / 100;
28	
29	const roundPremiumUp = (amount: number): number => Math.ceil(amount);
30	
31	const itemPremium = (item: Item): number => {
32	  const base = BASE_PREMIUM[item.type];
33	  return applyPercentSurcharge(base, FIRST_INSURANCE_SURCHARGE_PERCENT);
34	};
35	
36	const quotePremium = (step: QuoteStep): number => {
37	  const policyTotal = step.items.reduce((sum, item) => sum + itemPremium(item), 0);
38	  return roundPremiumUp(policyTotal + PROCESSING_FEE);
39	};
40	
41	export const processScenario = (scenario: Scenario): unknown => {
42	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step) }));
43	  return { results };
44	};
